// ❌ BAD - binding directly to EF entity exposes unwanted fields
app.MapGet("/products/{id}", async (int id, AppDbContext db) =>
    await db.Products.FindAsync(id));

// ✅ GOOD - use a service layer, return a typed result
app.MapGet("/products/{id}", async (int id, IProductService svc) =>
    await svc.FindAsync(id) is { } p ? Results.Ok(p) : Results.NotFound());

// ❌ BAD - middleware cannot read handler arguments or short-circuit per handler
app.Use(async (ctx, next) => { /* cannot inspect handler params */ await next(); });

// ✅ GOOD - endpoint filter sees handler args and is scoped per endpoint/group
app.MapPost("/orders", CreateOrder)
   .AddEndpointFilter(async (ctx, next) =>
   {
       var req = ctx.GetArgument<CreateOrderRequest>(0);
       if (req.Quantity <= 0) return Results.BadRequest("Quantity must be positive");
       return await next(ctx);
   });

// ❌ BAD - try/catch in every controller, scattered error logic
[HttpGet("{id}")] public async Task<Product> Get(int id) {
    try { return await _repo.FindAsync(id); }
    catch (NotFoundException) { /* duplicated everywhere */ throw; } }

// ✅ GOOD - centralised handler maps exceptions to status codes
public class AppExceptionHandler : IExceptionHandler {
    public async ValueTask<bool> TryHandleAsync(
        HttpContext ctx, Exception ex, CancellationToken ct) {
        var status = ex is NotFoundException ? 404 : 500;
        ctx.Response.StatusCode = status;
        await ctx.Response.WriteAsJsonAsync(
            new ProblemDetails { Title = ex.Message, Status = status }, ct);
        return true;
    }
}

// ❌ BAD - always returns healthy without checking dependencies
app.MapGet("/health", () => "healthy");

// ✅ GOOD - checks real dependencies, split by probe type
builder.Services.AddHealthChecks()
    .AddSqlServer(connString, tags: new[] { "readiness" })
    .AddRedis(redisConn, tags: new[] { "readiness" });
app.MapHealthChecks("/health/live");
app.MapHealthChecks("/health/ready",
    new HealthCheckOptions {
        Predicate = c => c.Tags.Contains("readiness")
    });

// ❌ BAD - injects scoped DbContext in constructor - captive dependency bug
public class InvoiceWorker : BackgroundService {
    public InvoiceWorker(AppDbContext db) { } }

// ✅ GOOD - creates a scope per iteration to safely use scoped services
public class InvoiceWorker : BackgroundService {
    private readonly IServiceScopeFactory _factory;
    public InvoiceWorker(IServiceScopeFactory factory) => _factory = factory;
    protected override async Task ExecuteAsync(CancellationToken ct) {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(30));
        while (await timer.WaitForNextTickAsync(ct)) {
            using var scope = _factory.CreateScope();
            var db = scope.ServiceProvider.GetRequiredService<AppDbContext>();
            await ProcessInvoicesAsync(db, ct);
        }
    }
}

// ❌ BAD - response caching only works if the client/proxy honours headers
[ResponseCache(Duration = 60)]
public IActionResult GetSalesReport() => Ok(_reportService.GetSales());

// ✅ GOOD - output caching stores server-side, supports tag eviction
builder.Services.AddOutputCache();
app.UseOutputCache();
app.MapGet("/reports/sales", GetSalesReport)
   .CacheOutput(p => p.Tag("reports").Expire(TimeSpan.FromMinutes(5)));
// On data update:
await _outputCache.EvictByTagAsync("reports", ct);

