// ❌ BAD - binding directly to EF entity lets client set Price and IsActive
[HttpPut("{id}")] public async Task<IActionResult> Update(int id, Product product) {
    _db.Entry(product).State = EntityState.Modified;
    await _db.SaveChangesAsync();
    return NoContent(); }

// ✅ GOOD - input DTO limits what client can change
public record UpdateProductRequest(string Name, string Description);
[HttpPut("{id}")] public async Task<IActionResult> Update(int id, UpdateProductRequest req) {
    var product = await _db.Products.FindAsync(id);
    product.Name = req.Name;
    product.Description = req.Description;
    await _db.SaveChangesAsync();
    return NoContent(); }

// ❌ BAD - blocks a thread while waiting for the database
[HttpGet("{id}")]
public IActionResult GetOrder(int id) {
    var order = _db.Orders.Find(id);
    return Ok(order); }

// ✅ GOOD - releases the thread during the DB wait
[HttpGet("{id}")]
public async Task<IActionResult> GetOrder(int id) {
    var order = await _db.Orders.FindAsync(id);
    return Ok(order); }
